/**
 * Auth pages — login, register, forgot-password, reset-password.
 * Detects which form exists on the page and binds handlers.
 * Uses page:init so it re-initializes on SPA navigation.
 */
$(document).on('page:init', function() {
    // ── Shared: password toggle ──
    function bindPasswordToggle(toggleId, inputId) {
        $('#' + toggleId).on('click', function() {
            var $input = $('#' + inputId);
            var isPassword = $input.attr('type') === 'password';
            $input.attr('type', isPassword ? 'text' : 'password');
            $(this).find('.eye-open').toggle(!isPassword);
            $(this).find('.eye-closed').toggle(isPassword);
            $(this).attr('aria-label', isPassword ? 'Hide password' : 'Show password');
        });
    }

    // ── Login ──
    if ($('#loginForm').length) {
        bindPasswordToggle('togglePassword', 'password');

        $('#loginForm').on('submit', function(e) {
            e.preventDefault();
            var $btn = $('#loginBtn').prop('disabled', true).text('Signing in...');
            $.ajax({
                url: '/api/auth/login',
                method: 'POST',
                contentType: 'application/json',
                data: JSON.stringify({
                    email: $('#email').val(),
                    password: $('#password').val()
                }),
                success: function(res) {
                    if (res.success) {
                        var dest = res.redirect || '/dashboard';
                        if (TinyShop.spa && TinyShop.spa._ready) {
                            TinyShop.spa._cache = {};
                            TinyShop.spa.go(dest);
                        } else {
                            window.location.href = dest;
                        }
                    }
                },
                error: function(xhr) {
                    var msg = xhr.responseJSON ? xhr.responseJSON.message : 'Something went wrong';
                    TinyShop.toast(msg, 'error');
                    $btn.prop('disabled', false).text('Sign In');
                }
            });
        });
    }

    // ── Register ──
    if ($('#registerForm').length) {
        bindPasswordToggle('togglePassword', 'password');

        function checkStrength(pw) {
            var score = 0;
            if (pw.length >= 6) score++;
            if (pw.length >= 10) score++;
            if (/[a-z]/.test(pw) && /[A-Z]/.test(pw)) score++;
            if (/\d/.test(pw)) score++;
            if (/[^a-zA-Z0-9]/.test(pw)) score++;
            return score;
        }

        $('#password').on('input', function() {
            var pw = $(this).val();
            var $bar = $('#passwordStrength');
            if (!pw) { $bar.hide(); return; }
            $bar.show();

            var score = checkStrength(pw);
            var fill = $('#strengthFill');
            var label = $('#strengthLabel');
            var levels = [
                { w: '10%', c: '#FF3B30', t: 'Too weak' },
                { w: '25%', c: '#FF3B30', t: 'Weak' },
                { w: '50%', c: '#FF9500', t: 'Fair' },
                { w: '75%', c: '#34C759', t: 'Good' },
                { w: '90%', c: '#30D158', t: 'Strong' },
                { w: '100%', c: '#30D158', t: 'Very strong' }
            ];
            var lvl = levels[Math.min(score, 5)];
            fill.css({ width: lvl.w, background: lvl.c });
            label.text(lvl.t).css('color', lvl.c);
        });

        $('#registerForm').on('submit', function(e) {
            e.preventDefault();
            var storeName = $('#storeName').val().trim();
            if (!storeName) { TinyShop.toast('Please enter a shop name', 'error'); return; }
            var $btn = $('#registerBtn').prop('disabled', true).text('Creating...');
            $.ajax({
                url: '/api/auth/register',
                method: 'POST',
                contentType: 'application/json',
                data: JSON.stringify({
                    store_name: storeName,
                    email: $('#email').val(),
                    password: $('#password').val()
                }),
                success: function(res) {
                    if (res.success) {
                        var dest = res.redirect || '/dashboard';
                        if (TinyShop.spa && TinyShop.spa._ready) {
                            TinyShop.spa._cache = {};
                            TinyShop.spa.go(dest);
                        } else {
                            window.location.href = dest;
                        }
                    }
                },
                error: function(xhr) {
                    var msg = xhr.responseJSON ? xhr.responseJSON.message : 'Something went wrong';
                    TinyShop.toast(msg, 'error');
                    $btn.prop('disabled', false).text('Create My Shop');
                }
            });
        });
    }

    // ── Forgot Password ──
    if ($('#forgotForm').length) {
        $('#forgotForm').on('submit', function(e) {
            e.preventDefault();

            var email = $('#email').val().trim();
            if (!email) {
                TinyShop.toast('Please enter your email address', 'error');
                return;
            }

            var $btn = $('#forgotBtn').prop('disabled', true).text('Sending...');

            $.ajax({
                url: '/api/auth/forgot-password',
                method: 'POST',
                contentType: 'application/json',
                data: JSON.stringify({ email: email }),
                success: function(res) {
                    if (res.success) {
                        $('#sentEmail').text(email);
                        $('#forgotForm').hide();
                        $('#successMessage').show();
                    }
                },
                error: function(xhr) {
                    var msg = xhr.responseJSON ? xhr.responseJSON.message : 'Something went wrong';
                    TinyShop.toast(msg, 'error');
                    $btn.prop('disabled', false).text('Send Reset Link');
                }
            });
        });
    }

    // ── Reset Password ──
    if ($('#resetForm').length) {
        bindPasswordToggle('togglePassword', 'password');
        bindPasswordToggle('togglePasswordConfirm', 'passwordConfirm');

        $('#resetForm').on('submit', function(e) {
            e.preventDefault();

            var password = $('#password').val();
            var confirm  = $('#passwordConfirm').val();
            var token    = $('#token').val();

            if (!password || password.length < 6) {
                TinyShop.toast('Password must be at least 6 characters', 'error');
                return;
            }

            if (password !== confirm) {
                TinyShop.toast('Passwords do not match', 'error');
                return;
            }

            var $btn = $('#resetBtn').prop('disabled', true).text('Resetting...');

            $.ajax({
                url: '/api/auth/reset-password',
                method: 'POST',
                contentType: 'application/json',
                data: JSON.stringify({
                    token: token,
                    password: password,
                    password_confirm: confirm
                }),
                success: function(res) {
                    if (res.success) {
                        TinyShop.toast('Password reset successfully! Redirecting...', 'success');
                        setTimeout(function() {
                            window.location.href = '/login';
                        }, 1500);
                    }
                },
                error: function(xhr) {
                    var msg = xhr.responseJSON ? xhr.responseJSON.message : 'Something went wrong';
                    TinyShop.toast(msg, 'error');
                    $btn.prop('disabled', false).text('Reset Password');
                }
            });
        });
    }
});
